/**
 * Validation helper module.
 *
 * Each exported function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN  = 1;
const NAME_MAX  = 100;
const EMAIL_MAX = 254;

/**
 * Validate a user id supplied via a URL parameter.
 * Express route params arrive as strings, so we coerce and range-check.
 *
 * @param {string|number} id
 * @returns {string[]} validation errors
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point in further checks
  }

  const num = Number(id);
  if (!Number.isFinite(num) || num !== Math.floor(num)) {
    errors.push('id must be a whole number');
  } else if (num < 1) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the `name` field from a request body.
 *
 * @param {*} name
 * @returns {string[]} validation errors
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors; // length checks are meaningless on non-strings
  }

  const trimmed = name.trim();
  if (trimmed.length < NAME_MIN) {
    errors.push(`name must be at least ${NAME_MIN} character`);
  }
  if (trimmed.length > NAME_MAX) {
    errors.push(`name must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate the `email` field from a request body.
 *
 * @param {*} email
 * @returns {string[]} validation errors
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > EMAIL_MAX) {
    errors.push(`email must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_RE.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate a full user object (name + email).
 * Used by POST (both fields required) and PUT (same rules apply).
 *
 * @param {{ name?: *, email?: * }} body
 * @returns {string[]} validation errors
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Express middleware factory.
 * Runs `validatorFn` against the merged request data and short-circuits
 * with a 400 response if any errors are found.
 *
 * Usage:
 *   router.post('/users', validate((req) => validateUserBody(req.body)), handler)
 *
 * @param {(req: import('express').Request) => string[]} validatorFn
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validate,
};

