/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID from a route parameter.
 * Must be a whole (integer) numeric value greater than 0.
 */
function validateId(rawId) {
  const errors = [];
  const num = Number(rawId);

  if (rawId === undefined || rawId === null || rawId === '') {
    errors.push('id is required');
  } else if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the body fields shared by POST and PUT /users.
 *
 * @param {object} body          - parsed request body
 * @param {boolean} requireAll   - true for POST (all fields required),
 *                                 false for PUT (at least one field required)
 */
function validateUserBody(body, requireAll = true) {
  const errors = [];

  // ── name ──────────────────────────────────────────────────────────────────
  if (body.name !== undefined) {
    if (typeof body.name !== 'string') {
      errors.push('name must be a string');
    } else if (body.name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (body.name.length > 100) {
      errors.push('name must not exceed 100 characters');
    }
  } else if (requireAll) {
    errors.push('name is required');
  }

  // ── email ─────────────────────────────────────────────────────────────────
  if (body.email !== undefined) {
    if (typeof body.email !== 'string') {
      errors.push('email must be a string');
    } else if (body.email.length > 254) {
      errors.push('email must not exceed 254 characters');
    } else if (!EMAIL_REGEX.test(body.email)) {
      errors.push('email must be a valid email address');
    }
  } else if (requireAll) {
    errors.push('email is required');
  }

  // ── at-least-one check for partial updates (PUT) ──────────────────────────
  if (!requireAll && body.name === undefined && body.email === undefined) {
    errors.push('at least one field (name, email) must be provided for update');
  }

  return errors;
}

/**
 * Send a 400 response with a structured error body.
 *
 * @param {object} res    - Express response object
 * @param {string[]} errors - array of validation error messages
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = { validateId, validateUserBody, sendValidationError };

