// validation.js – reusable input-validation helpers

/**
 * EMAIL_REGEX follows the practical subset of RFC 5321/5322 used by most
 * validators: local-part @ domain, where domain has at least one dot.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ─── Individual field validators ────────────────────────────────────────────

/**
 * Validates a user `id` path parameter.
 * Returns an error string when invalid, or null when valid.
 *
 * @param {*} value  – raw value (typically a string from req.params)
 * @returns {string|null}
 */
function validateId(value) {
  const num = Number(value);
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  if (!Number.isInteger(num) || num <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

/**
 * Validates a `name` field.
 * Returns an error string when invalid, or null when valid.
 *
 * @param {*} value  – raw value from the request body
 * @returns {string|null}
 */
function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return 'name must be at least 1 character long';
  }
  if (trimmed.length > 100) {
    return 'name must not exceed 100 characters';
  }
  return null;
}

/**
 * Validates an `email` field.
 * Returns an error string when invalid, or null when valid.
 *
 * @param {*} value  – raw value from the request body
 * @returns {string|null}
 */
function validateEmail(value) {
  if (value === undefined || value === null) {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > 254) {
    return 'email must not exceed 254 characters';
  }
  if (!EMAIL_REGEX.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

// ─── Composite schema validators ─────────────────────────────────────────────

/**
 * Validates the `:id` path parameter alone.
 * Returns null when all checks pass, or an object with an `errors` array.
 *
 * @param {object} params  – req.params
 * @returns {{ errors: string[] }|null}
 */
function validateIdParam(params) {
  const errors = [];
  const idError = validateId(params.id);
  if (idError) errors.push(idError);
  return errors.length > 0 ? { errors } : null;
}

/**
 * Validates the request body for creating a new user (POST /users).
 * Both `name` and `email` are required.
 *
 * @param {object} body  – req.body
 * @returns {{ errors: string[] }|null}
 */
function validateCreateUser(body) {
  const errors = [];
  const nameError = validateName(body.name);
  if (nameError) errors.push(nameError);
  const emailError = validateEmail(body.email);
  if (emailError) errors.push(emailError);
  return errors.length > 0 ? { errors } : null;
}

/**
 * Validates both the `:id` path parameter and the request body for updating
 * an existing user (PUT /users/:id).
 *
 * @param {object} params  – req.params
 * @param {object} body    – req.body
 * @returns {{ errors: string[] }|null}
 */
function validateUpdateUser(params, body) {
  const errors = [];
  const idError = validateId(params.id);
  if (idError) errors.push(idError);
  const nameError = validateName(body.name);
  if (nameError) errors.push(nameError);
  const emailError = validateEmail(body.email);
  if (emailError) errors.push(emailError);
  return errors.length > 0 ? { errors } : null;
}

// ─── Express middleware factory ───────────────────────────────────────────────

/**
 * Returns an Express middleware that runs `validatorFn` and, when it finds
 * errors, immediately responds with HTTP 400 and a JSON error body.
 *
 * Usage:
 *   router.post('/users', validate(validateCreateUser, 'body'), handler);
 *
 * @param {Function} validatorFn   – one of the composite validators above
 * @param {'body'|'params'|'both'} source
 *   'body'   → passes (req.body)
 *   'params' → passes (req.params)
 *   'both'   → passes (req.params, req.body)
 * @returns {Function} Express middleware
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    let result;
    if (source === 'params') {
      result = validatorFn(req.params);
    } else if (source === 'both') {
      result = validatorFn(req.params, req.body);
    } else {
      result = validatorFn(req.body);
    }

    if (result) {
      return res.status(400).json({
        error: 'Validation failed',
        errors: result.errors,
      });
    }
    next();
  };
}

module.exports = {
  // Individual validators (useful for unit testing)
  validateId,
  validateName,
  validateEmail,
  // Composite schema validators
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
  // Middleware factory
  validate,
};

