  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  if (!/^\d+$/.test(String(value)) || Number(value) <= 0) {
    errors.push(`${fieldName} must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a name field:
 *   - required
 *   - must be a string
 *   - length 1–100 characters
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  errors.push(...validateRequired(value, fieldName));
  if (errors.length > 0) return errors;

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length < 1 || value.length > 100) {
    errors.push(`${fieldName} must be between 1 and 100 characters`);
  }
  return errors;
}

/**
 * Validate an email field:
 *   - required
 *   - must be a string
 *   - must match email format
 *   - max 254 characters (RFC 5321)
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];
  errors.push(...validateRequired(value, fieldName));
  if (errors.length > 0) return errors;

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`${fieldName} must be 254 characters or fewer`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }
  return errors;
}

/**
 * Validate the full user body (name + email).
 * Pass `{ partial: true }` to skip "required" checks (useful for PATCH-style updates).
 */
function validateUserBody(body, { partial = false } = {}) {
  const errors = [];

  if (!partial || body.name !== undefined) {
    errors.push(...validateName(body.name, 'name'));
  }
  if (!partial || body.email !== undefined) {
    errors.push(...validateEmail(body.email, 'email'));
  }

  return errors;
}

/**
 * Express middleware factory — runs validators and sends a 400 with all errors
 * if any fail, otherwise calls next().
 *
 * Usage:
 *   router.post('/users', validate(() => validateUserBody(req.body)), handler)
 *
 * Because req is not in scope when the factory is called, accept a thunk instead:
 *   validate((req) => validateUserBody(req.body))
 */
function validate(getErrors) {
  return (req, res, next) => {
    const errors = getErrors(req);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validate,
};

