 * Returns an error string if the value is absent (undefined, null, or
 * empty-string after trimming), otherwise returns null.
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || String(value).trim() === '') {
    return `${fieldName} is required`;
  }
  return null;
}

/**
 * Returns an error string if value is not a finite integer > 0, otherwise null.
 * Accepts a raw string coming from req.params as well as a real number.
 */
function validateId(value, fieldName = 'id') {
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

/**
 * Returns an error string if value is not a non-empty string, otherwise null.
 */
function validateString(value, fieldName) {
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  return null;
}

/**
 * Returns an error string if the string's trimmed length is outside
 * [min, max], otherwise null.  Pass null for either bound to skip it.
 */
function validateStringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return null; // type already checked elsewhere
  const len = value.trim().length;
  if (min !== null && len < min) {
    return `${fieldName} must be at least ${min} character${min === 1 ? '' : 's'}`;
  }
  if (max !== null && len > max) {
    return `${fieldName} must be at most ${max} characters`;
  }
  return null;
}

/**
 * Returns an error string if value does not look like a valid e-mail address,
 * otherwise null.  Uses a conservative RFC 5321-aware regex.
 */
function validateEmail(value, fieldName = 'email') {
  if (typeof value !== 'string') return null; // type already checked elsewhere
  // local@domain — local part up to 64 chars, domain requires at least one dot
  const EMAIL_RE = /^[^\s@]{1,64}@[^\s@]+\.[^\s@]{2,}$/;
  if (!EMAIL_RE.test(value.trim())) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

