/**
 * Validate the request body when CREATING a user (all fields required).
 * @param {object} body – req.body
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateCreateUser(body) {
  const errors = [];
  const { name, email } = body || {};

  // --- name ---
  const nameRequired = validateRequired(name, 'name');
  if (nameRequired) {
    errors.push(nameRequired);
  } else {
    const nameType = validateString(name, 'name');
    if (nameType) {
      errors.push(nameType);
    } else {
      const nameLen = validateStringLength(name, 'name', 1, 100);
      if (nameLen) errors.push(nameLen);
    }
  }

  // --- email ---
  const emailRequired = validateRequired(email, 'email');
  if (emailRequired) {
    errors.push(emailRequired);
  } else {
    const emailType = validateString(email, 'email');
    if (emailType) {
      errors.push(emailType);
    } else {
      const emailLen = validateStringLength(email, 'email', null, 254);
      if (emailLen) errors.push(emailLen);
      const emailFmt = validateEmail(email, 'email');
      if (emailFmt) errors.push(emailFmt);
    }
  }

  return errors;
}

/**
 * Validate the request body when UPDATING a user (all provided fields are
 * validated, but at least one field must be present).
 * @param {object} body – req.body
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateUpdateUser(body) {
  const errors = [];
  const { name, email } = body || {};

  const hasName = name !== undefined && name !== null;
  const hasEmail = email !== undefined && email !== null;

  if (!hasName && !hasEmail) {
    errors.push('request body must include at least one of: name, email');
    return errors;
  }

  // --- name (optional, but validated when present) ---
  if (hasName) {
    const nameType = validateString(name, 'name');
    if (nameType) {
      errors.push(nameType);
    } else {
      const nameEmpty = validateRequired(name, 'name');
      if (nameEmpty) errors.push(nameEmpty);
      const nameLen = validateStringLength(name, 'name', 1, 100);
      if (nameLen) errors.push(nameLen);
    }
  }

  // --- email (optional, but validated when present) ---
  if (hasEmail) {
    const emailType = validateString(email, 'email');
    if (emailType) {
      errors.push(emailType);
    } else {
      const emailEmpty = validateRequired(email, 'email');
      if (emailEmpty) errors.push(emailEmpty);
      const emailLen = validateStringLength(email, 'email', null, 254);
      if (emailLen) errors.push(emailLen);
      const emailFmt = validateEmail(email, 'email');
      if (emailFmt) errors.push(emailFmt);
    }
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` against the request
 * and immediately responds with 400 + a descriptive errors array if any
 * validation fails, otherwise calls next().
 *
 * Usage:
 *   router.post('/users', validate(validateCreateUser, 'body'), handler)
 *
 * @param {function} validatorFn  – function that receives the data object
 * @param {'body'|'params'}  source  – which part of the request to validate
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    const data = source === 'params' ? req.params : req.body;
    const errors = validatorFn(data);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  // primitive helpers (exported for unit testing)
  validateRequired,
  validateId,
  validateString,
  validateStringLength,
  validateEmail,
  // composite validators
  validateParamId,
  validateCreateUser,
  validateUpdateUser,
  // middleware factory
  validate,
};

