/**
 * Validation helper module.
 * Each validator returns an array of error message strings.
 * An empty array means all checks passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a numeric ID (route param or body field).
 * Accepts a raw string or number; rejects floats, NaN, and non-numeric strings.
 *
 * @param {*} value   - The raw value to test.
 * @param {string} field - Field label used in error messages.
 * @returns {string[]}
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name string.
 *
 * @param {*} value
 * @param {string} field
 * @param {boolean} required - When false the field may be absent (useful for PATCH-style updates).
 * @returns {string[]}
 */
function validateName(value, field = 'name', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN) {
    errors.push(`"${field}" must be at least ${NAME_MIN} character`);
  }
  if (trimmed.length > NAME_MAX) {
    errors.push(`"${field}" must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate an email string.
 *
 * @param {*} value
 * @param {string} field
 * @param {boolean} required
 * @returns {string[]}
 */
function validateEmail(value, field = 'email', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > EMAIL_MAX) {
    errors.push(`"${field}" must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

/**
 * Send a 400 response with a structured error body.
 * Returns true so callers can do: if (sendValidationError(res, errors)) return;
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {boolean} Always true when errors are present.
 */
function sendValidationError(res, errors) {
  if (errors.length === 0) return false;

  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = { validateId, validateName, validateEmail, sendValidationError };
